mapper.insert:
INSERT INTO SETTLEMENT_EXPENSE ( EXPENSE_ID
                               , WS_ID
                               , PLANNER_ID
                               , EXPENSE_DATE
                               , ITEM
                               , PAYER
                               , AMOUNT
                               , STATUS
                               , REGIST_DT
                               , REGIST_ID)
VALUES ( #{expenseId,   jdbcType=VARCHAR}
       , #{wsId,        jdbcType=VARCHAR}
       , #{plannerId,   jdbcType=VARCHAR}
       , #{expenseDate, jdbcType=DATE}
       , #{item,        jdbcType=VARCHAR}
       , #{payer,       jdbcType=VARCHAR}
       , #{amount,      jdbcType=BIGINT}
       , #{status,      jdbcType=VARCHAR}
       , NOW()
       , #{registId,    jdbcType=VARCHAR})

mapper.select:
SELECT COUNT(*) > 0
FROM WORKSPACE_USER
WHERE WS_ID = #{workspaceId, jdbcType=VARCHAR}
  AND USER_ID = #{userId, jdbcType=VARCHAR}
